import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 30);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'Electronics', path: '/electronics' },
    { name: 'Electrical', path: '/electrical' },
    { name: 'Chemical', path: '/chemical' },
    { name: 'Industries', path: '/industries' },
    { name: 'About', path: '/about' },
  ];

  return (
    <>
      <nav className={`fixed w-full z-[110] transition-all duration-500 ${scrolled ? 'py-4 bg-white/10 backdrop-blur-2xl border-b border-white/10' : 'py-8 bg-transparent'}`}>
        <div className="max-w-[1800px] mx-auto px-8 flex justify-between items-center">

          {/* 1. MINIMAL LOGO */}
          <Link to="/" className="flex flex-col group">
            <span className="text-4xl font-black tracking-tighter leading-none group-hover:text-orange-600 transition-colors">
              H<span className="text-orange-600 group-hover:text-black transition-colors">.</span>
            </span>
            <span className="text-[7px] font-black uppercase tracking-[0.6em] text-gray-400">Hudson</span>
          </Link>

          {/* 2. DESKTOP LINKS (Hidden when scrolled for a cleaner look) */}
          <div className={`hidden lg:flex items-center gap-12 transition-all duration-500 ${scrolled ? 'opacity-0 scale-95 translate-y-2' : 'opacity-100 scale-100'}`}>
            {navLinks.map((link) => (
              <Link
                key={link.name}
                to={link.path}
                className="text-[11px] font-black uppercase tracking-[0.3em] text-gray-500 hover:text-orange-600 transition-all"
              >
                {link.name}
              </Link>
            ))}
          </div>

          {/* 3. MENU TRIGGER & CTA */}
          <div className="flex items-center gap-8">
            <button className="hidden md:block text-[11px] font-black uppercase tracking-[0.3em] border-b-2 border-orange-600 pb-1">
              Careers
            </button>

            {/* The "Menu" Button */}
            <button 
              onClick={() => setIsOpen(!isOpen)}
              className="group flex items-center gap-3 bg-gray-950 text-white pl-6 pr-2 py-2 rounded-full hover:bg-orange-600 transition-all"
            >
              <span className="text-[10px] font-black uppercase tracking-widest">Menu</span>
              <div className="h-8 w-8 bg-white/20 rounded-full flex items-center justify-center group-hover:rotate-180 transition-transform duration-500">
                <div className="relative w-4 h-4">
                  <span className={`absolute top-1/2 w-4 h-0.5 bg-white transition-all ${isOpen ? 'rotate-45' : '-translate-y-1'}`}></span>
                  <span className={`absolute top-1/2 w-4 h-0.5 bg-white transition-all ${isOpen ? '-rotate-45' : 'translate-y-1'}`}></span>
                </div>
              </div>
            </button>
          </div>
        </div>
      </nav>

      {/* 4. OVERLAY SIDE MENU (The Wow Factor) */}
      <div className={`fixed inset-0 z-[105] transition-all duration-700 ${isOpen ? 'visible' : 'invisible'}`}>
        {/* Blurred Backdrop */}
        <div 
          className={`absolute inset-0 bg-gray-950/40 backdrop-blur-xl transition-opacity duration-700 ${isOpen ? 'opacity-100' : 'opacity-0'}`}
          onClick={() => setIsOpen(false)}
        ></div>

        {/* Side Panel */}
        <div className={`absolute right-0 top-0 h-full w-full md:w-[450px] bg-white shadow-2xl transition-transform duration-700 ease-[cubic-bezier(0.85,0,0.15,1)] p-12 flex flex-col ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <div className="mt-24 space-y-2">
            <p className="text-gray-400 text-xs font-bold tracking-widest uppercase mb-6">Navigation</p>
            {navLinks.map((link, i) => (
              <Link
                key={i}
                to={link.path}
                onClick={() => setIsOpen(false)}
                className="group block text-5xl font-black text-gray-900 tracking-tighter hover:text-orange-600 transition-all overflow-hidden"
              >
                <span className="inline-block transition-transform duration-500 group-hover:-translate-y-full">
                  {link.name}
                </span>
                <span className="block transition-transform duration-500 group-hover:-translate-y-full text-orange-600">
                  {link.name}
                </span>
              </Link>
            ))}
          </div>

          <div className="mt-auto space-y-8">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <p className="text-gray-400 text-[10px] font-bold uppercase tracking-widest mb-2">Office</p>
                <p className="text-sm font-bold text-gray-900">Belapur, Navi Mumbai</p>
              </div>
              <div>
                <p className="text-gray-400 text-[10px] font-bold uppercase tracking-widest mb-2">Socials</p>
                <div className="flex gap-4 text-xs font-black">
                  <span className="hover:text-orange-600 cursor-pointer">LN</span>
                  <span className="hover:text-orange-600 cursor-pointer">TW</span>
                  <span className="hover:text-orange-600 cursor-pointer">IG</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

export default Navbar;
